import React, { createContext, useState, useContext, useEffect } from 'react';
import { authAPI } from '../services/api';

// Create the context
const AuthContext = createContext(null);

// ── AuthProvider wraps the entire app ────────────────────────
export const AuthProvider = ({ children }) => {
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);

  // Re-hydrate session on mount
  useEffect(() => {
    const verifySession = async () => {
      const token = localStorage.getItem('accessToken');
      if (token) {
        try {
          const res = await authAPI.getMe();
          setCurrentUser(res.data);
        } catch (err) {
          console.error("Session verification failed", err);
          setCurrentUser(null);
        }
      }
      setLoading(false);
    };

    verifySession();

    // Auto-handle 401 token expiry emitted from api.js
    const handleLogoutEvent = () => setCurrentUser(null);
    window.addEventListener('auth:logout', handleLogoutEvent);
    return () => window.removeEventListener('auth:logout', handleLogoutEvent);
  }, []);

  /** Log in: authenticates against backend API */
  const login = async (credentials) => {
    const res = await authAPI.login(credentials);
    setCurrentUser(res.data.user);
    return res;
  };

  /** Register: delegates to API and auto-logs in */
  const register = async (userData) => {
    const res = await authAPI.register(userData);
    if (res.data?.accessToken) {
      localStorage.setItem('accessToken', res.data.accessToken);
    }
    setCurrentUser(res.data.user);
    return res;
  };

  /** Log out: clears session from backend and local state */
  const logout = async () => {
    try {
      await authAPI.logout();
    } catch (err) {
      console.warn("Logout error from server:", err);
    }
    setCurrentUser(null);
  };

  const value = {
    currentUser,
    login,
    logout,
    register,
    isAuthenticated: !!currentUser,
  };

  // Prevent flicker during initial session verification
  if (loading) {
    return <div className="d-flex justify-content-center align-items-center vh-100"><div className="spinner-border text-primary"></div></div>;
  }

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

// Custom hook for convenience
export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};

export default AuthContext;
